const BASE_URL = "http://localhost:8000";

const handleResponse = async (res) => {
  if (!res.ok) {
    const err = await res.json().catch(() => ({ detail: res.statusText }));
    throw new Error(err.detail);
  }
  return res.json();
};

// ── TRAIN ───────────────────────────────────────────
export const trainModel = (payload) =>
  fetch(`${BASE_URL}/train`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      model_type: payload.model,
      hyperparameters: payload.hyperparams || {}
    }),
  }).then(handleResponse);

// ── PREDICT ─────────────────────────────────────────
export const predict = (features) =>
  fetch(`${BASE_URL}/predict`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ features }),
  }).then(handleResponse);

// ── UPLOAD ──────────────────────────────────────────
export const uploadDataset = (formData) =>
  fetch(`${BASE_URL}/upload`, {
    method: "POST",
    body: formData,
  }).then(handleResponse);

// ── DOWNLOAD ────────────────────────────────────────
export const downloadModel = async (modelId) => {
  const res = await fetch(`${BASE_URL}/download/${modelId}`);
  if (!res.ok) throw new Error("Download failed");
  return res.json();
};

// ── 🔥 FIX MISSING FUNCTIONS ────────────────────────

// HISTORY (mock simple → évite crash)
export const getHistory = () =>
  Promise.resolve([
    { model: "logistic_regression", accuracy: 0.82 },
    { model: "random_forest", accuracy: 0.87 }
  ]);

// AUTO TUNE (mock safe version)
export const autoTune = (payload) =>
  fetch(`${BASE_URL}/tune`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(payload),
  }).then(handleResponse);
